INSERT INTO public.photos VALUES (23025, 'Vista aâ”œÂ®rea 1990', 'Aâ”œÂ®rea visual capturada sobre el cauce del râ”œÂ¡o Ebro y orientada hacia su curso superior, cruzado sucesivamente por los puentes de Piedra, Santiago y La Almozara. En primer y a la izquierda, solares de la plaza de San Bruno inmediatos al Palacio Arzobispal y obras arqueolâ”œâ”‚gicas en la plaza de La Seo y reforma de la plaza del Pilar. Hacia la derecha, el puente de Piedra durante su â”œâ•‘ltima gran reforma inaugurada en abril de 1991.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”œÃ´RICO', 41.65691400, -0.87568700, '0101000020E6100000070951BEA005ECBF6C2409C215D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50201970418.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50201970418.webp', 'https://www.flickr.com/photos/zaragozaantigua/50201970418/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23075, 'Puente de Piedra 2004', 'Vicente Modesto Locual. 2004. Aâ”œÂ®rea vista centrada en el Puente de Piedra, con una expositiva presencia, en primer plano, del templo de El PIlar, el Ayuntamiento, la Lonja, y las dependencias del arzobispado anexas a su Palacio. Al otro lado del Puente, la margen izquierda, con unas riberas al Ebro aâ”œâ•‘n vâ”œÂ¡rgenes de intervenciâ”œâ”‚n: el Balcâ”œâ”‚n de San Lâ”œÃ­zaro, por ejemplo, parece un vergel. En el entorno de la calle Caminos del Norte (recuerdo del paso por ese lugar de los trenes que de la Estaciâ”œâ”‚n del Norte se dirigâ”œÂ¡an hacia Barcelona y Canfranc), mucha obra nueva (grandes bloques de viviendas), aâ”œâ•‘n sin terminar.', 2004, 2004, 2004, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15428464161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15428464161.webp', 'https://www.flickr.com/photos/zaragozaantigua/15428464161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23180, 'Arrabal 2000', '"La margen izquierda", â”œâ”‚leo sobre lienzo, Ignacio Mayayo, 2000. Vista del râ”œÂ¡o Ebro desde su margen derecha, entre los puentes de Piedra y de Hierro. La fachada al râ”œÂ¡o del Arrabal que ofrece esta pintura ha sido modificada radicalmente desde entonces. Fuente: ignaciomayayo.com', 2000, 2000, 2000, 'Siglo XXI', 'CASCO HISTâ”œÃ´RICO', 41.65789500, -0.87474300, '0101000020E61000002CF52C08E5FDEBBFD99942E735D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40405639694.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40405639694.webp', 'https://www.flickr.com/photos/zaragozaantigua/40405639694/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23261, 'Balsas de Ebro Viejo 1864', 'Interesante plano topogrâ”œÃ­fico firmado por Antonio Valiâ”œÂ®n que representa los terrenos y riegos de los propietarios Manuel Ezmir, Pedro Labarta y Gregorio Lisa, sitos en el tâ”œÂ®rmino del Rabal, partida de las Balsas de Ebro Viejo. A la derecha, representaciâ”œâ”‚n del puente de Piedra sobre el râ”œÂ¡o Ebro. En la parte superior, antigua calle del Rosario, que conducâ”œÂ¡a a la homâ”œâ”‚nima plaza del Rabal, y antigua calle de "canta-rranas", luego de las Ranas. En la parte inferior, camino de la Arboleda o de Ranillas junto a la arboleda de Macanaz. Fuente visual: Real Audiencia de Aragâ”œâ”‚n, AHPZ.', 1864, 1864, 1864, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65927200, -0.87577200, '0101000020E6100000941458005306ECBF92955F0663D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40066783175.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40066783175.webp', 'https://www.flickr.com/photos/zaragozaantigua/40066783175/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23812, 'El Pilar c.1904', 'Imagen capturada desde el puente de Piedra y centrada en el templo del Pilar con la torre de Nuestra Seâ”œâ–’ora del Pilar en construcciâ”œâ”‚n.', 1904, 1904, 1904, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65668700, -0.87594700, '0101000020E610000020F0C000C207ECBFAB5AD2510ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15725486376.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15725486376.webp', 'https://www.flickr.com/photos/zaragozaantigua/15725486376/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23875, 'El Pilar 1929', 'Paâ”œâ–’o de azulejos de cerâ”œÃ­mica representando a un aragonâ”œÂ®s que posa junto a la barandilla metâ”œÃ­lica del puente de Piedra, con el Pilar y el Ebro al fondo. Situado en la puerta de Aragâ”œâ”‚n de la plaza de Espaâ”œâ–’a de Sevilla, construida con motivo de la Exposiciâ”œâ”‚n Iberoamericana de 1929. Fuente: franconetti-aula-abierta.blogspot.com', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65717500, -0.87541000, '0101000020E61000006CEC12D55B03ECBFD95F764F1ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30949561710.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30949561710.webp', 'https://www.flickr.com/photos/zaragozaantigua/30949561710/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23884, 'El Pilar 1929', 'Foto: Miguel Marâ”œÂ¡n Chivite. Vista del Pilar desde el puente de Piedra. A la izquierda, el palacio de Ayerbe. Fuente: Heraldo de Aragâ”œâ”‚n.', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”œÃ´RICO', 41.65711600, -0.87552000, '0101000020E610000031CEDF844204ECBFD4D688601CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31641993175.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31641993175.webp', 'https://www.flickr.com/photos/zaragozaantigua/31641993175/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23891, 'Puente de Piedra y Pilar 1907', 'Postal editada por Fototipia Madriguera (Barcelona) en 1907, con una foto del puente de Piedra y el Pilar, cuya segunda torre aparece terminada y con el andamiaje sin retirar. En primer plano se aprecian vallas de obras de acondicionamiento del acceso al puente desde el Arrabal y del pretil de San Lâ”œÃ­zaro. Fuente: Heraldo de Aragâ”œâ”‚n.', 1907, 1907, 1907, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65794900, -0.87504800, '0101000020E610000044C4CDA96400ECBFCCB73EAC37D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32462232375.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32462232375.webp', 'https://www.flickr.com/photos/zaragozaantigua/32462232375/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23899, 'Ovejas arrabaleras 1954', 'Curiosa imagen capturada desde la arboleda de Macanaz, junto a la ribera del Ebro donde unas ovejas se aventuran a abrevar de forma plâ”œÃ­cida, mientras el resto de la grey ramonea por el entorno, a la derecha y fuera de plano. Al otro lado, o margen derecha, vista del templo del Pilar con las obras de recrecimiento de las torres norteâ”œâ–’as (la de Santa Leonor a la izquierda, la de San Francisco de Borja a la derecha). Ademâ”œÃ­s y a la izquierda, estructura de la nueva Casa Consistorial en la parte recayente al paseo de Echegaray a Caballero, menos adelantada que la escâ”œÂ®nica fachada recayente a la plaza del Pilar. Esta postal forma parte de una experimental etapa transitoria entre las tradicionales postales en blanco y negro y las modernas en color, en la que los originales fotogrâ”œÃ­ficos en blanco y negro se pintaban a mano y luego se imprimâ”œÂ¡an "en color". La denominaciâ”œâ”‚n de la editorial que distribuyâ”œâ”‚ esta imagen, P. Esperâ”œâ”‚n, hacâ”œÂ¡a referencia a uno de los pioneros de la fotografâ”œÂ¡a en Espaâ”œâ–’a en el â”œâ•‘ltimo tercio del siglo XIX: el francâ”œÂ®s Alfred Esperon, espaâ”œâ–’olizado Alfredo Esperâ”œâ”‚n, coetâ”œÃ­neo de Jean Laurent.', 1954, 1954, 1954, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65837200, -0.87596800, '0101000020E6100000FDF50A0BEE07ECBF124DA08845D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48859007223.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48859007223.webp', 'https://www.flickr.com/photos/zaragozaantigua/48859007223/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23906, 'Puente de Piedra 1903', 'Imagen capturada a espaldas del cuartel de san Lâ”œÃ­zaro con el objetivo dirigido hacia el puente de Piedra jalonado por los postes de la reciâ”œÂ®n electrificada lâ”œÂ¡nea del tranvâ”œÂ¡a Arrabal. En el templo del Pilar progresan en su primera fase los andamios de obra del recrecimiento de la torre de Nâ”¬Â¬ Sâ”¬Â¬ del Pilar, proyectada por Josâ”œÂ® de Yarza Echenique con la colaboraciâ”œâ”‚n de Julio Bravo Folch y Ricardo Magdalena Tabuenca.', 1903, 1903, 1903, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65745900, -0.87526900, '0101000020E6100000E57B46223402ECBFFEBAD39D27D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51008667026.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51008667026.webp', 'https://www.flickr.com/photos/zaragozaantigua/51008667026/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24054, 'La Virgen al pozo 1975', 'Un grupo de submarinistas del Club Aragonâ”œÂ®s de Actividades Subacuâ”œÃ­ticas, presidido por Manuel de la Figuera, sumergiâ”œâ”‚ en octubre de 1975 una estatua de plomo de la Virgen del Pilar en el pozo de San Lâ”œÃ­zaro, a 18 metros de profundidad. Eran Benito Poderâ”œâ”‚s, Alberto Marquet, Josâ”œÂ® Miguel Buera y Antonio Ramâ”œÂ¡rez. Para ello contaron con la colaboraciâ”œâ”‚n de miembros del Grupo de Espeleologâ”œÂ¡a de Aragâ”œâ”‚n, que se descolgaron con la imagen hasta la embarcaciâ”œâ”‚n. Tambiâ”œÂ®n estuvo presente la secciâ”œâ”‚n juvenil de la Cruz Roja, para asistir en caso de accidente. Y el Regimiento de Pontoneros aportâ”œâ”‚ las lanchas. En esta ocasiâ”œâ”‚n, no hubo participaciâ”œâ”‚n del Cuerpo de Bomberos. Hubo bendiciâ”œâ”‚n previa a cargo de un sacerdote flotante, momento que recoge la imagen, y numeroso pâ”œâ•‘blico congregado en el puente de Piedra. Al fondo, la torre de la Seo.', 1975, 1975, 1975, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65756800, -0.87469100, '0101000020E61000008D60E3FA77FDEBBFB4722F302BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31569827114.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31569827114.webp', 'https://www.flickr.com/photos/zaragozaantigua/31569827114/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24159, 'Zaragoza de gala 1919', '"Zaragoza de gala...". Ilustraciâ”œâ”‚n de A. Dâ”œÂ¡az Domâ”œÂ¡nguez para la portada del Heraldo de Aragâ”œâ”‚n del 21 de mayo de 1919, al dâ”œÂ¡a siguiente de la inauguraciâ”œâ”‚n de la Exposiciâ”œâ”‚n Hispano-Francesa de Bellas Artes en la Lonja. A la derecha, el puente de Piedra. Fuente: Heraldo de Aragâ”œâ”‚n.', 1919, 1919, 1919, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65712700, -0.87540000, '0101000020E610000088635DDC4603ECBFC828CFBC1CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32741619876.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32741619876.webp', 'https://www.flickr.com/photos/zaragozaantigua/32741619876/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
