INSERT INTO public.photos VALUES (24731, 'Calle del Sobrarbe c.1900', 'Estudio Coyne/ DARA. Principios siglo XX. Imagen desde el principio de la calle Sobrarbe, con la iglesia parroquial de Altabâ”œÃ­s a la derecha. Hemos volteado horizontalmente la imagen original, para que los edificios aparezcan en su sitio canâ”œâ”‚nico, como por ejemplo la fâ”œÃ­brica de pan y luego el taller de carreterâ”œÂ¡a que a la izquierda se ubicaba en los bajos del inmueble del nâ”¬â•‘ 15 de la calle.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65858400, -0.87511200, '0101000020E6100000F3C98AE1EA00ECBF9DD5027B4CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14794207078.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14794207078.webp', 'https://www.flickr.com/photos/zaragozaantigua/14794207078/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24735, 'Puente de Piedra 1813', 'Bridge of the Ebro, Zaragoza. Eduard Hanke Locker, 1813. Publicado en Views in Spain, 1824. Desde la ribera derecha, Interesante vista del puente de Piedra que presenta el estado de la arcada inmediata a la margen derecha tras las reparaciones provisionales que mediante maderos permitieron reabrir al trâ”œÃ­nsito el puente tras ser destruida el 8 de julio tras la salida de la guarniciâ”œâ”‚n francesa. La restauraciâ”œâ”‚n final del puente se realizâ”œâ”‚ a principios de 1814, justo para permitir que por â”œÂ®l transitara la comitiva del rey Fernando VII durante su visita a la ciudad en abril de ese aâ”œâ–’o. En la margen izquierda se destaca el convento de San Lâ”œÃ­zaro. Fuente: amable aportaciâ”œâ”‚n de Josâ”œÂ® Luis Cintora.', 1813, 1813, 1813, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65694900, -0.87549300, '0101000020E6100000CB0F5CE50904ECBFE811A3E716D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15085000060.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15085000060.webp', 'https://www.flickr.com/photos/zaragozaantigua/15085000060/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24749, 'Puente de Piedra 1897', 'Imagen fotogrâ”œÃ­fica convertida en estampa costumbrista tâ”œâ”‚pica. Centraremos el objetivo en el fondo, con el templo del Pilar de una sola torre, la de Santiago. En el Puente de Piedra, protegido por los cuatro pâ”œÂ®treos leones, como hasta 1917. En el suelo, con seâ”œâ–’ales de los raâ”œÂ¡les del reciente (fue inaugurado en marzo) ramal del tranvâ”œÂ¡a que conectaba la ciudad con el Arrabal, subdividido en dos lâ”œÂ¡neas: la primera, o directa, por la calle Sobrarbe (hacia la derecha). La segunda, o lâ”œÂ¡nea suplementaria, seguâ”œÂ¡a la carretera de Barcelona y terminaba en el patio de la estaciâ”œâ”‚n de ferrocarril del Norte (hacia donde se dirige el paisano). Y en la vivienda de la derecha, que formaba parte de la calle Sobrarbe, justo al lado de las vâ”œÂ¡as que por debajo permitâ”œÂ¡an circular al ferrocarril hacia el puente de la Almozara. Fuente visual: "La Revista Moderna", Madrid.', 1897, 1897, 1897, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65822000, -0.87480700, '0101000020E6100000DBFAE93F6BFEEBBF5CC98E8D40D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15838488112.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15838488112.webp', 'https://www.flickr.com/photos/zaragozaantigua/15838488112/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24774, 'Calle Sobrarbe 1964', 'Rururbana imagen durante la celebraciâ”œâ”‚n de San Isidro Labrador por la franquista "Hermandad Sindical de Labradores y Ganaderos", que aprovechaba su nulo gasto energâ”œÂ®tico, reivindicativo y movilizador, durante el resto del aâ”œâ–’o, para concentrar su fogosidad en esta fecha. Ese aâ”œâ–’o, ademâ”œÃ­s, aâ”œâ–’adâ”œÂ¡a a la celebraciâ”œâ”‚n la oficial campaâ”œâ–’a de los "25 aâ”œâ–’os de Paz", como ilustra la pancarta de la carroza mecanizada de la imagen, llegada de Villamayor, en su alegre desfilar por la calle de Sobrarbe, hacia el Puente de Piedra, como parte de la festiva caravana agrâ”œÂ¡cola-nacionalista. Al fondo, las torres de la iglesia parroquial de Nuestra Seâ”œâ–’ora de Altabâ”œÃ­s. Fuente visual: Gerardo Sancho Ramo, Archivo Pâ”œâ•‘blico Municipal.', 1964, 1964, 1964, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65859100, -0.87447400, '0101000020E61000004679E6E5B0FBEBBF5038BBB54CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24558564680.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24558564680.webp', 'https://www.flickr.com/photos/zaragozaantigua/24558564680/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24787, 'Puente de Piedra 1968', 'Imagen de la unidad nâ”¬â•‘ 12 de la lâ”œÂ¡nea de trolebuses "Gâ”œÃ­llego" pasando por el puente de Piedra, en su ruta hacia la terminal de la calle de la Verâ”œâ”‚nica. Se trata de uno de los "BUT" de 1 piso venidos de Londres, a los que deberâ”œÂ¡an haber acompaâ”œâ–’ado algunos "BUT" de 2 pisos, pero la baja altura del puente del ferrocarril que cruzaba la avenida de Cataluâ”œâ–’a, desaconsejâ”œâ”‚ su uso en esta lâ”œÂ¡nea. A la izquierda, el recientâ”œÂ¡simo gran bloque de viviendas de los nâ”œâ•‘meros 2, 4 y 6 de la calle Sixto Celorrio. Al fondo, la iglesia parroquial de Altabâ”œÃ­s en la calle de Sobrarbe, y el convento de Terciarias Franciscanas de Altabâ”œÃ­s. A la derecha, la plazuela arbolada inmediata al cuartel de San Lâ”œÃ­zaro. En el firme, trazado de las vâ”œÂ¡as de la lâ”œÂ¡nea 10 "Arrabal-Academia" del tranvâ”œÂ¡a. Fuente visual: Foto Bernard Harrison, a travâ”œÂ®s de www.forotrenes.com/', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65746800, -0.87519800, '0101000020E610000097C9703C9F01ECBF511553E927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30484724153.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30484724153.webp', 'https://www.flickr.com/photos/zaragozaantigua/30484724153/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21092, 'Monasterio de Santa Fe 1871', '"Ruinas de Santa Fe". Dibujo de Santiago Ramâ”œâ”‚n y Cajal, 2 de octubre de 1871. Representa los restos del monasterio cisterciense de Santa Marâ”œÂ¡a en Santa Fe de Huerva, enclave perteneciente al municipio de Zaragoza, adscrito al distrito de Casablanca. A la derecha, vista parcial de la torre de la iglesia barroca.', 1871, 1871, 1871, 'Siglo XIX', NULL, 41.57696100, -0.95160400, '0101000020E6100000E3C4573B8A73EEBFA208A9DBD9C94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53395684049.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53395684049.webp', 'https://www.flickr.com/photos/zaragozaantigua/53395684049/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24806, '1968 Arrabal', 'Imagen centrada en la unidad nâ”¬â•‘ 161 de la tranviaria serie "Topolinos", en servicio en la lâ”œÂ¡nea 4 "Arrabal", regresando a la terminal de la plaza de la Seo. La captura se ha realizado en el puente de Piedra, con el telâ”œâ”‚n de fondo de algunas edificaciones referenciales de la margen izquierda, como la iglesia de Altabâ”œÃ­s, el cuartel de San Lâ”œÃ­zaro, y el novâ”œÂ¡simo bloque del 2-4-6 de la calle Sixto Celorrio. Tras el tranvâ”œÂ¡a, un trolebâ”œâ•‘s, bien de la lâ”œÂ¡nea "Gâ”œÃ­llego", bien de la "Barrio Jesâ”œâ•‘s", hacia su terminal en la calle de la Verâ”œâ”‚nica. Tras la clausura de la lâ”œÂ¡nea "Arrabal" a finales de 1971, este "Topolino" fue desguazado. Fuente visual: foto Bernard Harrison, en www.flickr.com/photos/30937/19043809034/', 1968, 1968, 1968, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65778100, -0.87503100, '0101000020E6100000C18EFF024100ECBF1077F52A32D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33752800645.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33752800645.webp', 'https://www.flickr.com/photos/zaragozaantigua/33752800645/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24826, 'Margen izquierda c.1931', 'Imagen capturada desde la altura de la torre de la Seo y orientada hacia la margen izquierda o Arrabal. En primer tâ”œÂ®rmino, patio del Seminario metropolitano y Universidad Pontificia anexo al Palacio Arzobispal. Centra la escena el puente de Piedra y el râ”œÂ¡o Ebro. En la ribera norte, la calle del Sobrarbe anuncia la carretera de Zaragoza a Huesca junto al cauce al aire de la acequia de Juslibol, y hacia la derecha la avenida de Cataluâ”œâ–’a, con el cuartel de San Lâ”œÃ­zaro, la estaciâ”œâ”‚n del Arrabal y el gran polâ”œÂ¡gono industrial conformado por Maquinista y Fundiciones del Ebro, S.A., la Nueva Harinera y la Harinera del Arrabal. Hacia la izquierda, el camino de Ranillas y la calle de Sixto Celorrio que conduce al parque de Ibort.', 1931, 1931, 1931, 'Anos 30', 'CASCO HISTâ”œÃ´RICO', 41.65737400, -0.87526900, '0101000020E6100000E57B46223402ECBFCF9ECBD424D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50708983541.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50708983541.webp', 'https://www.flickr.com/photos/zaragozaantigua/50708983541/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24827, 'Comparsa Gigantes 1978', 'Imagen centrada en la comparsa de Gigantes durante las Fiestas del Pilar que, proveniente del puente de Piedra, se encamina en descenso hacia la calle de Sixto Celorrio. Con el incomparable fondo del templo del Pilar desfilan con su atâ”œÃ­vica parsimonia los personajes del Rey, la Reina, Don Quijote, Dulcinea, Chino, Negra, Gastâ”œâ”‚n de Bearn y la Bearnesa. Estos fueron los â”œâ•‘ltimos "pilares" del antiguo râ”œÂ®gimen, cuando la â”œâ•‘ltima corporaciâ”œâ”‚n heredada del franquismo montâ”œâ”‚ una "programaciâ”œâ”‚n" centrada en la ofrenda de flores a la Virgen del Pilar y el clasista ceremonial de la "reina de las fiestas" (Montserrat Genzor) elegida entre las familiares elites que gobiernan esta ciudad. Unas paralelas "Fiestas Populares" intentaron insuflar aires nuevos con mâ”œÃ­s ilusiâ”œâ”‚n que medios. Tras las elecciones municipales de 1979, este panorama cambiâ”œâ”‚ de forma importante.', 1978, 1978, 1978, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65822000, -0.87492500, '0101000020E6100000567DAEB662FFEBBF5CC98E8D40D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50862393197.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50862393197.webp', 'https://www.flickr.com/photos/zaragozaantigua/50862393197/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24869, 'Vuelo sobre el Ebro 1911', 'Imagen capturada desde el puente de Hierro y centrada en el tradicional fondo escâ”œÂ®nico que sobre el râ”œÂ¡o Ebro formaban el puente de Piedra y la monumental fachada fluvial de la margen derecha, desde el Seminario metropolitano hasta el templo del Pilar. El singular elemento que diferencia esta fotografâ”œÂ¡a de otras similares es el monoplano Blâ”œÂ®riot pilotado por el francâ”œÂ®s Joseph Gaget que en la parte superior derecha sobrevuela el râ”œÂ¡o Ebro hacia el oriente durante la disputa con el tambiâ”œÂ®n francâ”œÂ®s Andrâ”œÂ® Frey de la "Copa Zaragoza" disputada el 27 de abril, tras la finalizaciâ”œâ”‚n de la exitosa "II Semana de la Aviaciâ”œâ”‚n" celebrada entre el 17 y el 25 de abril de 1911. Realizados sus respectivos vuelos y regresados ambos al aerâ”œâ”‚dromo de Valdespartera, el jurado formado por el marquâ”œÂ®s de Arlanza, el barâ”œâ”‚n de Benasque y los seâ”œâ–’ores Juncosa, Escoriaza, Valenzuela, La Rosa y Macipe, decidiâ”œâ”‚ que la copa donada por el Sindicato de Iniciativas de Zaragoza recayera en Joseph Gaget.', 1911, 1911, 1911, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65680100, -0.87457100, '0101000020E6100000E4F560527CFCEBBF747D1F0E12D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51688359798.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51688359798.webp', 'https://www.flickr.com/photos/zaragozaantigua/51688359798/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24889, 'Monumento a Santo Dominguito de Val 1958', 'Obra del escultor Antonio Bueno e inaugurado en 1951 junto al cuartel de San Lâ”œÃ­zaro (en la foto, detrâ”œÃ­s), fue retirado en los aâ”œâ–’os 80 cuando el lugar se transformâ”œâ”‚ en el Balcâ”œâ”‚n de San Lâ”œÃ­zaro. Foto de diciembre de 1958. Fuente: elbalcondesanlazaro.blogspot.com.es/2013/12/monumento-san...', 1958, 1958, 1958, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65808700, -0.87458400, '0101000020E61000000C5BB39597FCEBBF1D76DF313CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15022737919.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15022737919.webp', 'https://www.flickr.com/photos/zaragozaantigua/15022737919/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25073, 'Monumento a Santo Dominguito de Val 1976', 'Domingo ("Dominguito") es un legendario monaguillo de la catedral de San Salvador convertido por el oficial antisemitismo medieval de la iglesia catâ”œâ”‚lica en "Santo Dominguito de Val". La atroz fâ”œÃ­bula que justificâ”œâ”‚ su canonizaciâ”œâ”‚n es una suma de monstruosidades de tal calibre, que la propia iglesia catâ”œâ”‚lica, tras el Concilio Vaticano II, convino en suprimir su culto, aunque sigue siendo practicado por el catolicismo ultra. En la imagen, monumento que el nacional catolicismo local dedicâ”œâ”‚ a esta mâ”œâ”‚rbida historia, casi 700 aâ”œâ–’os despuâ”œÂ®s de su supuesto acontecimiento. Es obra de Antonio Bueno, y habâ”œÂ¡a sido inaugurado en 1951 en una glorieta entre el puente de Piedra y el cuartel de San Lâ”œÃ­zaro (en la imagen, al fondo). Justo detrâ”œÃ­s habâ”œÂ¡a una fuente de agua potable, tal vez lo â”œâ•‘nico sano del conjunto. Allâ”œÂ¡ permaneciâ”œâ”‚ hasta que a mediados de los aâ”œâ–’os 80 la plaza donde se ubicaba fue remodelada, sin que tras esa obra este monumento fuera repuesto.', 1976, 1976, 1976, 'Anos 70', 'CASCO HISTâ”œÃ´RICO', 41.65808700, -0.87458400, '0101000020E61000000C5BB39597FCEBBF1D76DF313CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18653379440.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18653379440.webp', 'https://www.flickr.com/photos/zaragozaantigua/18653379440/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21240, 'Conservas Marraco 1908', 'Fâ”œÃ­brica de conservas vegetales de Manuel Marraco, luego Marraco Hermanos, en el barrio de Monzalbarba de Zaragoza, 1908. Ubicada cerca de la estaciâ”œâ”‚n ferroviaria Utebo-Monzalbarba, contaba con cultivos propios. Empezâ”œâ”‚ su actividad en 1895. Entre sus especialidades, guisantes al estilo francâ”œÂ®s y purâ”œÂ® de tomate concentrado por evaporaciâ”œâ”‚n al vacâ”œÂ¡o. Fuente: Mâ”¬Â¬ Pilar Biel Ibâ”œÃ­â”œâ–’ez, Zaragoza y la industrializaciâ”œâ”‚n: la arquitectura industrial 1875-1926, IFC, 2004.', 1908, 1908, 1908, 'Anos 1900', NULL, 41.70046300, -0.98148100, '0101000020E6100000ECA694D74A68EFBF6E8786C5A8D94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19638715286.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19638715286.webp', 'https://www.flickr.com/photos/zaragozaantigua/19638715286/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25109, 'The Stone Bridge 1891', '"The stone bridge at Saragossa. The destructive floods in Spain." Dibujo del puente de piedra, como parte de la portada del "The Illustrated London News", de setiembre de 1891, informando de unas "desastrosas" y "destructivas" inundaciones que habâ”œÂ¡an tenido lugar en Espaâ”œâ–’a. Sucede que este dibujo es una copia literal de una fotografâ”œÂ¡a tomada un par de aâ”œâ–’os antes por J. Lâ”œÂ®vy et Cie, y no precisamente en un momento en que el râ”œÂ¡o se hubiera salido de madre: el antiguo azud espumea. Fuente visual: Fondo Documental Histâ”œâ”‚rico de las Cortes de Aragâ”œâ”‚n.', 1891, 1891, 1891, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65769900, -0.87507600, '0101000020E6100000C07630629F00ECBF53CE177B2FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14877110002.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14877110002.webp', 'https://www.flickr.com/photos/zaragozaantigua/14877110002/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25135, 'Puente de Piedra 1890', 'Vista del Puente de Piedra y el Pilar. Cromo de la colecciâ”œâ”‚n del "Autâ”œÂ®ntico extracto de carne Liebig", publicado en Parâ”œÂ¡s en 1899. La imagen del Pilar es anterior a la de la finalizaciâ”œâ”‚n del remate de la torre de Santiago del Pilar.', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19149319049.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19149319049.webp', 'https://www.flickr.com/photos/zaragozaantigua/19149319049/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25142, 'El Pilar c.1910', 'Cartel publicitario a colores, sobre chapa litografiada, y en relieve, realizado por "Litografâ”œÂ¡a La Artâ”œÂ¡stica, Coruâ”œâ–’a" para la reciâ”œÂ®n inaugurada fâ”œÃ­brica de galletas "Patria". El dibujo estâ”œÃ­ situado en una de las localizaciones estâ”œÃ­ndar de la ciudad: el puente de Piedra sobre el râ”œÂ¡o Ebro, con la catedral de El Pilar como fondo de imagen, ya recrecida su segunda torre, la de "Nâ”¬Â¬ Sâ”¬Â¬ del Pilar". Sobre el puente, el "camiâ”œâ”‚n-automâ”œâ”‚vil" para trâ”œÃ­fico de mercancâ”œÂ¡as de la empresa anunciante, coincide con un par de indâ”œÂ¡genas, caracterizados con tâ”œâ”‚picos ropajes folclâ”œâ”‚ricos, en dulce situaciâ”œâ”‚n, pues ella le ofrece un irresistible bizcocho troquelado de la metâ”œÃ­lica caja que guarda bajo el brazo. â”œÃ«l, entrecierra los ojos ante la prometedora circunstancia, y se aproxima sumiso, dâ”œâ”‚cil. Fuente: Colecciâ”œâ”‚n Marâ”œÂ¡a Tausiet.', 1910, 1910, 1910, 'Anos 10', 'CASCO HISTâ”œÃ´RICO', 41.65694900, -0.87549300, '0101000020E6100000CB0F5CE50904ECBFE811A3E716D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24136224013.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24136224013.webp', 'https://www.flickr.com/photos/zaragozaantigua/24136224013/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25148, 'Puente de Piedra 1813', 'Bridge of the Ebro, Zaragoza. Dibujo original de Eduard Hanke Locker, publicado en Londres dentro de la obra "Views in Spain, 1824", por Rodwell and Martin, e impreso por C. Hullmandel. Al fondo, el convento mercedario de San Lâ”œÃ­zaro, y ruinas provocadas por la explosiâ”œâ”‚n de la â”œâ•‘ltima arcada del puente de Piedra, provocada por las tropas francesas en retirada. Destacan los provisionales apaâ”œâ–’os en madera para permitir el trâ”œÃ­nsito por el puente. Inmediata, la antigua iglesia parroquial de Altabâ”œÃ­s. Fuente: www.cortesaragon.es/', 1813, 1813, 1813, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65746800, -0.87519800, '0101000020E610000097C9703C9F01ECBF511553E927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30598949751.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30598949751.webp', 'https://www.flickr.com/photos/zaragozaantigua/30598949751/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25192, 'Puente Colgante Ebro 1838', 'El penoso estado del puente de Piedra llevâ”œâ”‚ en 1838 al Ayuntamiento a convocar un concurso para construir uno nuevo que sustituyera al "viejo", que serâ”œÂ¡a derribado. La imagen representa uno de los proyectos presentados, firmado por Federico Angâ”œÃ­n y Juan de la Vega, que imitando modelos franceses, propone un puente colgante con dos tramos y sostenido por alambres amarrados en las mâ”œÃ­rgenes. Al estar previsto el derribo del puente de Piedra, aâ”œâ–’adâ”œÂ¡an al proyecto cuatro pedestales y dos pilares monumentales con decoraciones alusivas al heroâ”œÂ¡smo de los Sitios, todo para dar realce escâ”œÂ®nico a la que serâ”œÂ¡a principal entrada a la ciudad desde el otro lado del Ebro. Nuevos leones sobre los pedestales, mâ”œÃ­s grandes, pero igual de sedentes, contemplarâ”œÂ¡an el trâ”œÃ­nsito del Ebro. La ruina econâ”œâ”‚mica municipal aparcâ”œâ”‚ al resoluciâ”œâ”‚n del concurso, y los proyectos presentados quedaron archivados. El viejo puente de Piedra superviviâ”œâ”‚. Fuente visual: AMZ. Fuente textual: Mâ”¬Â¬ Pilar Biel, "Los puentes metâ”œÃ­licos de carretera sobre el Ebro en la provincia de Zaragoza", Artigrama, 2000.', 1838, 1838, 1838, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65735400, -0.87596600, '0101000020E6100000D00D4DD9E907ECBF88F2052D24D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19561141906.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19561141906.webp', 'https://www.flickr.com/photos/zaragozaantigua/19561141906/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25409, 'Puerta del â”œÃ¼ngel 1866', 'Foto: Mariano Jâ”œâ•‘dez. Puerta del â”œÃ¼ngel, puente de Piedra y basâ”œÂ¡lica del Pilar. Fuente: Antiguas puertas de Zaragoza, IFC, 2013.', 1866, 1866, 1866, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65739400, -0.87494000, '0101000020E6100000ACCABE2B82FFEBBF164B917C25D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14978759632.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14978759632.webp', 'https://www.flickr.com/photos/zaragozaantigua/14978759632/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25410, 'Voladura del puente de Piedra 1813', 'Voladura en incendio del puente de Piedra de Zaragoza la noche del 9 de julio de 1813, al ser abandonada por los franceses. Aguafuerte anâ”œâ”‚nimo, atribuido a M. Latassa. Terminaban asâ”œÂ¡ cuatro aâ”œâ–’os de gobierno francâ”œÂ®s en la ciudad. Segâ”œâ•‘n la Guâ”œÂ¡a de Zaragoza de 1860, Ã”Ã‡Â£Durante la permanencia de los franceses en Zaragoza, se mejorâ”œâ”‚ la ciudad y sus afueras; proyectâ”œÃ­ndose vastas obras de pâ”œâ•‘blica utilidad, que los acontecimientos de la guerra impidieron verificar. Propagandistas y creadores, dejaron en Zaragoza huellas de su paso; y, como en todas partes, semillas de otras ideas que en su dâ”œÂ¡a habâ”œÂ¡an de germinar. Aquellas semillas brotaron a principios del aâ”œâ–’o 1820, proclamâ”œÃ­ndose en Zaragoza la Constituciâ”œâ”‚nÃ”Ã‡Ã˜. Mâ”œÃ­s informaciâ”œâ”‚n: tausiet.blogspot.com.es/2016/01/contrasitios.html', 1813, 1813, 1813, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65715400, -0.87538600, '0101000020E61000004A0A2C802903ECBFC1374D9F1DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15019494481.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15019494481.webp', 'https://www.flickr.com/photos/zaragozaantigua/15019494481/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25411, 'Puente de Piedra 1960', 'Archivo Municipal. Gerardo Sancho Ramo. 1960. Imagen de uno de los tajamares del puente de Piedra cuando, aprovechando el bajo caudal del estâ”œÂ¡o, eran aprovechados como lugar de refresco de pies. Esta mirada cenital permite tambiâ”œÂ®n apreciar las metâ”œÃ­licas grapas con que se reforzaba la uniâ”œâ”‚n entre los bloques de piedra de la base del puente.', 1960, 1960, 1960, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65781100, -0.87480700, '0101000020E6100000DBFAE93F6BFEEBBF7BF99D2633D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15162728973.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15162728973.webp', 'https://www.flickr.com/photos/zaragozaantigua/15162728973/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23773, 'Empresarium 2006', 'Recreaciâ”œâ”‚n del polâ”œÂ¡gono industrial Empresarium de La Cartuja Baja (350 hectâ”œÃ­reas), inaugurado en 2006. Este complejo fue ideado en 1990, cuando Tudor se trasladâ”œâ”‚ a la zona. Se ubica entre el barranco de las Casetas (izquierda) y el Canal Imperial de Aragâ”œâ”‚n (derecha). Estâ”œÃ­ atravesado por la lâ”œÂ¡nea ferroviaria a Barcelona. Al fondo a la derecha se halla el Parque Tecnolâ”œâ”‚gico de Reciclado Lâ”œâ”‚pez Soriano (850 hectâ”œÃ­reas), ya en el distrito de Torrero-La Paz. La imagen promocional, colmatada de naves industriales y con amplias zonas verdes, dista del estado real una dâ”œÂ®cada despuâ”œÂ®s. Fuente visual: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', NULL, 41.58959600, -0.81776000, '0101000020E61000004243FF04172BEABF1CEDB8E177CB4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31699829484.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31699829484.webp', 'https://www.flickr.com/photos/zaragozaantigua/31699829484/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25413, 'Puente de Piedra 1955', 'Por el puente de Piedra y entre poco trâ”œÃ­fico circula un trolebâ”œâ•‘s de la lâ”œÂ¡nea Barrio Jesâ”œâ•‘s que habâ”œÂ¡a sustituido recientemente a la homâ”œâ”‚nima lâ”œÂ¡nea tranviaria. La calle del Sobrarbe, tras el puente que salva la trinchera del enlace del ferrocarril, asciende por el barrio del Arrabal pasando junto al convento de Santa Isabel, el grupo escolar Câ”œÃ­ndido Domingo y la iglesia de Altabâ”œÃ­s, y poco despuâ”œÂ®s del acceso al patio de carros de la estaciâ”œâ”‚n del Norte o Arrabal, se convierte ya en la carretera de Huesca. Al fondo se perfilan las chimeneas de la fâ”œÃ­brica de la Uniâ”œâ”‚n Alcoholera Espaâ”œâ–’ola, y en las alturas del Cascajo se eleva el moderno Dispensario Central Antituberculoso, con sus cinco plantas y cuatrocientas camas llenas de pacientes como consecuencia de la endemia tuberculosa de la â”œÂ®poca. Fuente Visual: Editorial Arribas, AMZ', 1955, 1955, 1955, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15174915899.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15174915899.webp', 'https://www.flickr.com/photos/zaragozaantigua/15174915899/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25420, 'Puente de Piedra 1444', '"Puente de Piedra, Zaragoza (the bridge on the left)" Charles Holroyd, 1906 "At left, view of the Puente de Piedra; at right, Nuestra Seâ”œâ–’ora del Pilar, Zaragoza". Aguafuerte de muy elevada ensoâ”œâ–’aciâ”œâ”‚n româ”œÃ­ntica, imaginando el aspecto de la ciudad en algâ”œâ•‘n momento de su baja edad media, con el puente de Piedra sobre el râ”œÂ¡o Ebro, y una murallas que causaban pavor a los potenciales enemigos. Por mâ”œÃ­s que lo buscamos, no encontramos traza del Pilar (ni de Santa Marâ”œÂ¡a la Mayor, su antecedente): nos lo impide la arboleda. Fuente visual: www.britishmuseum.org/', 1444, 1444, 1444, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65694900, -0.87549300, '0101000020E6100000CB0F5CE50904ECBFE811A3E716D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17504263688.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17504263688.webp', 'https://www.flickr.com/photos/zaragozaantigua/17504263688/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25427, 'Puente de Piedra y el Pilar 1962', 'Puente de Piedra, con el Pilar al fondo en julio de 1962, aâ”œâ–’o siguiente de terminar de colocarle una torre en cada esquina. Fuente: www.flickr.com/photos/122511173@N05/13699516045', 1962, 1962, 1962, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20657984246.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20657984246.webp', 'https://www.flickr.com/photos/zaragozaantigua/20657984246/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25428, 'Puente de Piedra 1958', 'Tranvâ”œÂ¡a de la lâ”œÂ¡nea 10 "Academia" a su paso por el puente de Piedra de Zaragoza. Al fondo, la Lonja y el Pilar. Fuente: elbalcondesanlazaro.blogspot.com', 1958, 1958, 1958, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65694900, -0.87549300, '0101000020E6100000CB0F5CE50904ECBFE811A3E716D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20901246296.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20901246296.webp', 'https://www.flickr.com/photos/zaragozaantigua/20901246296/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25429, 'Puente de Piedra 1965', 'Foto: Fernando Llauradâ”œâ”‚, 10-4-1965. Un trolebâ”œâ•‘s BUT cruza el puente de Piedra de Zaragoza. Al fondo a la izquierda, la arboleda de Macanaz. Fuente: www.facebook.com/photo.php?fbid=409282679236402&set=p...', 1965, 1965, 1965, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65665500, -0.87583900, '0101000020E610000088F6B182DF06ECBFA0E062450DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20904827633.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20904827633.webp', 'https://www.flickr.com/photos/zaragozaantigua/20904827633/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25441, 'Puente de Piedra 1877', 'Interesante imagen del puente de Piedra y el râ”œÂ¡o Ebro capturadas desde la margen derecha, desde cierta altura. Inmediato, silueteado por el templo del Pilar, el paseo del Ebro aparece bien despejado, antes de plantaciones y tendido tranviario. El puente de Piedra sigue siendo el â”œâ•‘nico puente de trâ”œÃ­nsito y conexiâ”œâ”‚n en esta parte de la ciudad. En el Arrabal, destaca al fondo la desmochada torre del antiguo convento franciscano de Jesâ”œâ•‘s. A su derecha, restos del antiguo convento mercedario de San Lâ”œÃ­zaro, ya como parte del recinto militarizado y convertido hacâ”œÂ¡a poco en cuartel del ejâ”œÂ®rcito. Despunta, incluso, algo mâ”œÃ­s hacia la derecha, el ilustrado molino de harina que antes estuviera junto al puente de Piedra. En el puente, en temporada de aguas bajas, visual del efecto producido por los restos del antiguo azud. Fuente visual: Jean Laurent & Câ”œÂ¡a (AHPZ-DARA)', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65742400, -0.87530300, '0101000020E6100000EBE6E26F7B02ECBF81CD397826D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28303352100.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28303352100.webp', 'https://www.flickr.com/photos/zaragozaantigua/28303352100/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25448, 'Puente de Piedra 1967', 'Imagen centrada en el obraje abierto en el puente de Piedra, capturada en direcciâ”œâ”‚n hacia la margen izquierda. Al fondo, y a la izquierda, el ascendente esqueleto que vertebra el nuevo gran bloque de viviendas de los nâ”œâ•‘meros 2, 4 y 6 de la calle Sixto Celorrio. Al fondo, las pareadas cupulillas de la iglesia parroquial de Altabâ”œÃ­s en la calle de Sobrarbe. En el firme, flanqueando la zanja, trazado de las vâ”œÂ¡as de la tranviaria lâ”œÂ¡nea 10 "Arrabal-Academia", una de cuyas unidades ha pasado recientemente en direcciâ”œâ”‚n a la castrense academia. Parece ser que la transitoria interrupciâ”œâ”‚n de trâ”œÃ­fico rodado, en esta ocasiâ”œâ”‚n, no supuso el colapso social, econâ”œâ”‚mico y cultural de la margen izquierda de la ciudad. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1967, 1967, 1967, 'Anos 60', 'CASCO HISTâ”œÃ´RICO', 41.65712700, -0.87540000, '0101000020E610000088635DDC4603ECBFC828CFBC1CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32596430234.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32596430234.webp', 'https://www.flickr.com/photos/zaragozaantigua/32596430234/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25449, 'Fuegos artificales 1952', 'Anochece en esta escena tomada desde las traseras del cuartel de San Lâ”œÃ­zaro junto a la margen izquierda del râ”œÂ¡o Ebro, y centrada en el puente de Piedra lleno de paisanos observando los fuegos artificiales lanzados desde la arboleda de Macanaz. A la izquierda, la estructura del nuevo palacio municipal y el templo del Pilar en el que se destacan las luminosas jaculatorias que coronan sus dos torres y las câ”œâ•‘pulas mayores y menores. Emerge en obras el esqueleto de la nueva torre de Santa Leonor, mientras que la de San Francisco de Borja aâ”œâ•‘n no ha sido iniciada. Al fondo, entre las arcadas del puente de Piedra, la pasarela de Macanaz tambiâ”œÂ®n repleta de observantes de las ruidosas luminarias noctunas. Fuente visual: AMZ', 1952, 1952, 1952, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65712700, -0.87540000, '0101000020E610000088635DDC4603ECBFC828CFBC1CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32978126618.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32978126618.webp', 'https://www.flickr.com/photos/zaragozaantigua/32978126618/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25451, 'Puente de Piedra 1882', 'Dibujo al natural de Juan Comba y diseâ”œâ–’o de Bernardo Rico que ilustra el paso del puente de Piedra por la castrense comitiva que a lomos de caballo acompaâ”œâ–’aba al rey Alfonso XII en direcciâ”œâ”‚n al campo de San Gregorio a unas maniobras y evoluciones militares incluidas en los festejos por el inicio de las obras del ferrocarril de Canfranc. La escena ha sido capturada desde la margen izquierda del râ”œÂ¡o Ebro, con el telâ”œâ”‚n de fondo de la Seo, el palacio arzobispal (donde se hospedaba el rey), el Seminario Conciliar, la calle de la Lonja, y la Casa Ayuntamiento y Lonja. Sobre el puente, postes del tendido y farolas elâ”œÂ®ctricas. Fuente visual: La Ilustraciâ”œâ”‚n espaâ”œâ–’ola y americana (1882)', 1882, 1882, 1882, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34384976430.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34384976430.webp', 'https://www.flickr.com/photos/zaragozaantigua/34384976430/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25455, 'Bajo el puente de Piedra c.1950', 'Escena capturada bajo la cuarta arcada del puente de Piedra (originalmente, la quinta), y centrada en el templo del Pilar poco antes del inicio del recrecimiento de las torres ribereâ”œâ–’as. En primer tâ”œÂ®rmino, la pâ”œÂ®trea solera iluminada por la solana. A la izquierda, vista residual del esqueleto del "palacio municipal", o nuevo ayuntamiento de la ciudad. Sobre el canicular cauce del râ”œÂ¡o Ebro, un par de barcas navegan sin necesidad de dragado, y en la orilla algunas personas buscan el refresco junto al agua. Fuente visual: www.todocoleccion.net/', 1950, 1950, 1950, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65712700, -0.87540000, '0101000020E610000088635DDC4603ECBFC828CFBC1CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46092985534.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46092985534.webp', 'https://www.flickr.com/photos/zaragozaantigua/46092985534/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25460, 'Vista c.1885', 'Vista del puente de Piedra sobre un râ”œÂ¡o Ebro con apreciable caudal de agua, centrada con el fondo del templo del Pilar caracterizado por su notable conjunto de câ”œâ•‘pulas entre las que despunta levemente la inacabada torre de Santiago. A la izquierda, la Torre Nueva desmochada de su remate barroco en forma de triple chapitel, emerge sobre la nueva gran casa del marquâ”œÂ®s de Ayerbe esquinera con la calle de Alfonso I que albergaba el Pasaje del Comercio y de la Industria, y de la veterana casa del mismo marquâ”œÂ®s ubicada en la calle del Pilar. Junto al puente, el edificio de la Casa Consistorial y la Lonja.', 1885, 1885, 1885, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65686500, -0.87465700, '0101000020E610000088F546AD30FDEBBF8B71FE2614D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51398454762.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51398454762.webp', 'https://www.flickr.com/photos/zaragozaantigua/51398454762/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25461, 'Vista desde Altabas c.1874', 'Tercera de las vistas capturadas por Jean Laurent y Câ”œÂ¡a. que forma parte del extraordinario trâ”œÂ¡ptico titulado "Vista general desde Altabas". Esta toma se centra en el puente de Piedra y la fachada de la ciudad al Ebro desde las Casas Consistoriales hasta San Juan de los Panetes. La gran câ”œâ•‘pula central del Pilar y las câ”œâ•‘pulas del Coro aparecen ya terminadas.', 1874, 1874, 1874, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65713800, -0.87545100, '0101000020E61000001004C8D0B103ECBFBC7A15191DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54141492733.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54141492733.webp', 'https://www.flickr.com/photos/zaragozaantigua/54141492733/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25532, 'El Pilar 1908', 'Foto Santiago Ramâ”œâ”‚n y Cajal, Diputaciâ”œâ”‚n de Zaragoza, 1908. Toma desde el Puente de Piedra del râ”œÂ¡o Ebro y el Pilar. En primer plano, a la izquierda, la Cruz en Memoria de Basilio Boggiero, Santiago Sas y el Barâ”œâ”‚n de Warsage, levantada segâ”œâ•‘n diseâ”œâ–’o de Ricardo Magdalena en 1908, el mismo aâ”œâ–’o en el que el premio Nobel realizâ”œâ”‚ la fotografâ”œÂ¡a. Fuente: web.dpz.es/arscatalogi.es/', 1908, 1908, 1908, 'Anos 1900', 'CASCO HISTâ”œÃ´RICO', 41.65761400, -0.87543400, '0101000020E61000008ECEF9298E03ECBF25B20FB22CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15713909180.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15713909180.webp', 'https://www.flickr.com/photos/zaragozaantigua/15713909180/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25535, 'Vista 1959', 'Desde los nuevos bloques de viviendas de la calle de Cecilio Navarro junto al puente de Hierro y en altura, una buena vista panorâ”œÃ­mica y en detalle de las riberas del Ebro, tanto de la derecha, donde progresa significativamente la obra del nuevo ayuntamiento y el recrecimiento de las dos nuevas torres ribereâ”œâ–’as del Pilar, como de la margen izquierda, donde destaca el cuartel de San Lâ”œÃ­zaro, el monumento a Santo Dominguito de Val, la vâ”œÂ¡a del enlace ferroviario entre las estaciones del Norte y de Delicias, la arboleda de Macanaz y el barrio de la Ortilla. Sobre el Ebro, el puente de Piedra, la pasarela peatonal y al fondo el puente del ferrocarril.', 1959, 1959, 1959, 'Anos 50', 'CASCO HISTâ”œÃ´RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16095665676.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16095665676.webp', 'https://www.flickr.com/photos/zaragozaantigua/16095665676/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
